	//
	// fetchOrder
	//     {
	//       "history_id": 641452639,
	//       "order_id": 315992721,
	//       "client_order_id": "ade1aa6...",
	//       "symbol": "XPL",
	//       "side": "ask",
	//       "price": "1.0865",
	//       "initial_amount": "984",
	//       "filled_amount": "0",
	//       "cancelled_amount": "984",
